module RefModule(
    input clk,
    input rst_n,
    input en,
    output reg [3:0] count
);

    reg [3:0] obf_count_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            obf_count_reg <= 4'b1111;
        end else if (en) begin
            obf_count_reg <= obf_count_reg - 1;
        end
    end

    assign count = obf_count_reg;

endmodule
